import * as fs from 'fs';
import * as path from 'path';
import { fileURLToPath } from 'url';
import { execSync } from 'child_process';
import { AcousticEngine } from '../../aether/src/acoustic-siphon';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

/**
 * Acoustic Sentence Speaker
 * Uses Topological Intent Siphoning (Lucas Resonance) to resolve phonemes.
 */

// Lucas Sequence for Topological Suction
const lucas = (n: number): number => {
  let a = 2, b = 1;
  for (let i = 0; i < n; i++) { [a, b] = [b, a + b]; }
  return a % 1000000;
};

async function main() {
  const sentence = process.argv[2] || "Hello world";
  const voiceName = process.argv[3] || "Sophia";

  console.log('============================================================');
  console.log(` Speaking: ${sentence} (Voice: ${voiceName})`);
  console.log('============================================================\n');

  const engine = new AcousticEngine();
  engine.setVoice(voiceName);

  const projectRoot = path.resolve(__dirname, '../../..');
  const geometriesPath = path.join(projectRoot, 'open-source/aether/src/phoneme-geometries.json');
  const phonemeCatalog = JSON.parse(fs.readFileSync(geometriesPath, 'utf8'));

  // Build Lucas Trace Map for the Reservoir (Death of Space)
  const traceMap: Record<string, number> = {};
  phonemeCatalog.forEach((spec: any, index: number) => {
    traceMap[spec.id] = lucas(index + 1);
  });

  // 1. TOPOLOGICAL INTENT SIPHONING
  // Instead of a dictionary, we suck intent through Lucas resonance.
  const sequence = textToPhonemeSequence(sentence);
  console.log('[SIPHON] Intent Siphoned: ' + sequence.join(' '));

  let finalAudio = new Float32Array(0);

  // 2. GLOBAL PROSODY ENGINE
  const totalPhonemes = sequence.length;
  const getF0 = (index: number) => {
    const base = (engine as any).currentVoice.baseF0;
    const progress = index / totalPhonemes;
    let f0 = base * (1.1 - progress * 0.2);
    if (index > 2 && index < 6) f0 *= 1.15; 
    return f0;
  };

  for (let i = 0; i < sequence.length; i++) {
    const p = sequence[i];
    const trace = traceMap[p];
    if (trace === undefined) continue;

    const nextP = sequence[i + 1];
    const nextTrace = nextP ? traceMap[nextP] : undefined;
    const nextDebt = nextTrace !== undefined ? {
      expectedCoordinate: 0,
      expectedBoundaryTrace: nextTrace,
      timestamp_gravity: 0
    } : undefined;

    console.log('[SIPHON] Condensing ' + p + '...');
    const phonemeAudio = await engine.condense({
      expectedCoordinate: 0,
      expectedBoundaryTrace: trace,
      timestamp_gravity: 0
    }, nextDebt, getF0(i));

    const newBuffer = new Float32Array(finalAudio.length + phonemeAudio.length);
    newBuffer.set(finalAudio);
    newBuffer.set(phonemeAudio, finalAudio.length);
    finalAudio = newBuffer;
  }

  // Save and Play
  const outputWav = path.join(__dirname, 'sentence-output.wav');
  const int16Buffer = new Int16Array(finalAudio.length);
  for (let i = 0; i < finalAudio.length; i++) {
    int16Buffer[i] = Math.max(-32768, Math.min(32767, finalAudio[i] * 32767));
  }
  
  writeWav(outputWav, int16Buffer, 24000);
  console.log('\nSaved to: ' + outputWav);
  
  try {
    execSync('afplay ' + outputWav);
  } catch (e) {}
}

/**
 * Robust Heuristic G2P Logic (The Base Attractor)
 */
function textToPhonemeSequence(text: string): string[] {
  const words = text.toLowerCase().replace(/[^a-z\s]/g, '').split(/\s+/).filter(w => w.length > 0);
  const result: string[] = [];
  for (const word of words) {
    result.push(...wordToPhonemesHeuristic(word));
    result.push('SIL');
  }
  return result;
}

function wordToPhonemesHeuristic(word: string): string[] {
  const result: string[] = [];
  let i = 0;
  const len = word.length;
  const isVowelChar = (c: string) => 'aeiouy'.includes(c);
  
  // Dynamic Silent-E: word ends in 'e' or 'es' preceded by C-V
  const hasSilentE = (len > 2 && word.endsWith('e') && !isVowelChar(word[len-2]) && isVowelChar(word[len-3])) ||
                     (len > 3 && word.endsWith('es') && !isVowelChar(word[len-3]) && isVowelChar(word[len-4]));

  while (i < len) {
    const remaining = word.slice(i);
    const ch = word[i];
    const next = word[i + 1] || '';
    const prev = i > 0 ? word[i - 1] : '';
    
    // 0. Suffixes (Terminal logic)
    if (word.endsWith('ed') && i === len - 2 && len > 3) {
      if (prev === 't' || prev === 'd') { result.push('AH', 'D'); }
      else if ('pkfshcx'.includes(prev)) { result.push('T'); }
      else { result.push('D'); }
      i += 2; continue;
    }

    // 1. Digraphs and Vowel Clusters
    if (remaining.startsWith('through')) { result.push('TH', 'R', 'UW'); i += 7; continue; }
    if (remaining.startsWith('tion')) { result.push('SH', 'AH', 'N'); i += 4; continue; }
    if (remaining.startsWith('sion')) { 
      result.push(isVowelChar(prev) ? 'ZH' : 'SH', 'AH', 'N'); 
      i += 4; continue; 
    }
    if (remaining.startsWith('th')) { result.push('DH'); i += 2; continue; }
    if (remaining.startsWith('sh')) { result.push('SH'); i += 2; continue; }
    if (remaining.startsWith('ch')) { result.push('CH'); i += 2; continue; }
    if (remaining.startsWith('ight')) { result.push('AY', 'T'); i += 4; continue; }
    if (remaining.startsWith('ook')) { result.push('UH', 'K'); i += 3; continue; }
    if (remaining.startsWith('ing')) { result.push('IH', 'NG'); i += 3; continue; }
    if (remaining.startsWith('ng')) { result.push('NG'); i += 2; continue; }
    if (remaining.startsWith('ear')) { result.push('IY', 'R'); i += 3; continue; }
    if (remaining.startsWith('air')) { result.push('EH', 'R'); i += 3; continue; }
    if (remaining.startsWith('ee') || remaining.startsWith('ea')) { result.push('IY'); i += 2; continue; }
    if (remaining.startsWith('oo')) { result.push('UW'); i += 2; continue; }
    if (remaining.startsWith('ay') || remaining.startsWith('ai')) { result.push('EY'); i += 2; continue; }
    
    if (remaining.startsWith('ou') || remaining.startsWith('ow')) { 
      // Structural 'AW' attractor (out, down, cow) vs 'OW' (show, soul)
      if ('ntdl'.includes(word[i + 2] || '')) { result.push('AW'); }
      else { result.push('OW'); }
      i += 2; continue; 
    }

    // 1.5 Consonant Digraphs & Silent Clusters
    if (remaining.startsWith('ph')) { result.push('F'); i += 2; continue; }
    if (remaining.startsWith('kn') && i === 0) { result.push('N'); i += 2; continue; }
    if (remaining.startsWith('wr') && i === 0) { result.push('R'); i += 2; continue; }
    if (remaining.startsWith('wh')) { result.push('W'); i += 2; continue; }
    if (remaining.startsWith('gh')) {
      if (i === 0) { result.push('G'); }
      else if (prev === 'u' && (word[i-2] === 'a' || word[i-2] === 'o')) {
         if (i + 2 === len) result.push('F'); 
      }
      i += 2; continue;
    }

    // 2. Vowel + R (r-colored vowels)
    const isTerminal = (i + 2 === len) || (i + 3 === len && word[i+2] === 's');

    if (ch === 'a' && next === 'r') {
      if (hasSilentE && i + 2 === len - 1) { result.push('EH', 'R'); i += 2; continue; }
      result.push('AA', 'R'); i += 2; continue;
    }
    if (ch === 'o' && next === 'r') {
      if (isTerminal) { result.push('ER'); i += 2; continue; }
      else { result.push('AO'); i++; continue; }
    }
    if (ch === 'e' && next === 'r') { result.push('ER'); i += 2; continue; }
    if (ch === 'i' && next === 'r') {
      if (hasSilentE && i + 2 === len - 1) { result.push('AY', 'R'); i += 2; continue; }
      result.push('ER'); i += 2; continue;
    }
    if (ch === 'u' && next === 'r') { result.push('ER'); i += 2; continue; }

    // 3. Consonants and Clusters
    if (ch === 'c') {
      if (next === 'h') { result.push('CH'); i += 2; continue; }
      if ('eiy'.includes(next)) { result.push('S'); }
      else { result.push('K'); }
    }
    else if (ch === 'g') {
      if ('eiy'.includes(next)) { result.push('JH'); } 
      else { result.push('G'); }
    }
    else if (ch === 'j') { result.push('JH'); }
    else if (ch === 's') {
      if (isVowelChar(prev) && isVowelChar(next)) { result.push('Z'); }
      else { result.push('S'); }
    }
    else if (ch === 'q') {
      if (next === 'u') { result.push('K', 'W'); i += 2; continue; }
      else { result.push('K'); }
    }
    else if (ch === 'y' && i === 0 && isVowelChar(next)) {
      result.push('Y');
    }
    else if (ch === 'x') { result.push('K', 'S'); }
    else if (ch === 'b') { result.push('B'); }
    else if (ch === 'd') { result.push('D'); }
    else if (ch === 'f') { result.push('F'); }
    else if (ch === 'h') { result.push('HH'); }
    else if (ch === 'k') { result.push('K'); }
    else if (ch === 'l') { result.push('L'); }
    else if (ch === 'm') { result.push('M'); }
    else if (ch === 'n') { result.push('N'); }
    else if (ch === 'p') { result.push('P'); }
    else if (ch === 'r') { result.push('R'); }
    else if (ch === 't') { result.push('T'); }
    else if (ch === 'v') { result.push('V'); }
    else if (ch === 'w') { result.push('W'); }
    else if (ch === 'z') { result.push('Z'); }
    
    // 4. Individual Vowels (Fallback)
    else if (isVowelChar(ch)) {
      if (ch === 'e' && i === len - 1 && hasSilentE) { /* Skip */ }
      else if (ch === 'a') result.push(i === len - 1 ? 'AH' : (hasSilentE ? 'EY' : 'AE'));
      else if (ch === 'e') result.push(i === len - 1 && len <= 3 ? 'AH' : 'EH');
      else if (ch === 'i') result.push(hasSilentE ? 'AY' : 'IH');
      else if (ch === 'o') result.push(i === len - 1 ? 'OW' : (hasSilentE ? 'OW' : 'AA'));
      else if (ch === 'u') result.push(hasSilentE ? 'UW' : 'AH');
      else if (ch === 'y') result.push(len <= 3 ? 'AY' : 'IY');
    }
    i++;
  }
  return result;
}

function writeWav(filename: string, samples: Int16Array, sampleRate: number) {
  const buffer = Buffer.alloc(44 + samples.length * 2);
  buffer.write('RIFF', 0);
  buffer.writeUInt32LE(36 + samples.length * 2, 4);
  buffer.write('WAVE', 8);
  buffer.write('fmt ', 12);
  buffer.writeUInt32LE(16, 16);
  buffer.writeUInt16LE(1, 20);
  buffer.writeUInt16LE(1, 22);
  buffer.writeUInt32LE(sampleRate, 24);
  buffer.writeUInt32LE(sampleRate * 2, 28);
  buffer.writeUInt16LE(2, 32);
  buffer.writeUInt16LE(16, 34);
  buffer.write('data', 36);
  buffer.writeUInt32LE(samples.length * 2, 40);
  for (let i = 0; i < samples.length; i++) {
    buffer.writeInt16LE(samples[i], 44 + i * 2);
  }
  fs.writeFileSync(filename, buffer);
}

main().catch(console.error);